import { __decorate } from "tslib";
import { Component, Input } from '@angular/core';
export let TestButtonComponent = class TestButtonComponent {
    constructor() {
        this.label = 'Click me';
        this.backgroundColor = '#eee';
    }
    static { this.propDecorators = {
        label: [{ type: Input }],
        backgroundColor: [{ type: Input }]
    }; }
};
TestButtonComponent = __decorate([
    Component({
        selector: 'lib-test-button',
        template: `
    <button [style.background-color]="backgroundColor">
      {{ label }}
    </button>
  `,
        standalone: true
    })
], TestButtonComponent);
